command:
mkdir -p space .claude-tdd-pro/space && printf 'collected:
  - {id: space-activity-commits, value: 200, prev: 50}
  - {id: space-perf-rubric-pass-rate, value: 0.80, prev: 0.81}
' > .claude-tdd-pro/space/collected.yaml && printf 'metrics:
  - {id: space-activity-commits, dimension: activity}
  - {id: space-perf-rubric-pass-rate, dimension: performance}
' > space/metrics.yaml && printf 'dimensions: {activity: {opt_in: true, enabled: true}, performance: {enabled: true}}
share: never
' > space/config.yaml && bash "$CLAUDE_PLUGIN_ROOT/commands/space-report.sh" --metrics space/metrics.yaml --collected .claude-tdd-pro/space/collected.yaml --config space/config.yaml 2>out.txt && grep -q 'counter-goodhart' out.txt && grep -q 'activity_spike_without_quality_change' out.txt && echo ok 1>&2
